14: package dispatch
15: 
16: import (
17: 	"encoding/json"
18: 	"fmt"
19: 	"sort"
20: 	"strconv"
21: 	"strings"
22: 	"time"
23: 
24: 	"github.com/prometheus/common/model"
25: 
26: 	"github.com/prometheus/alertmanager/config"
27: 	"github.com/prometheus/alertmanager/pkg/labels"
28: )
29: 
30: // DefaultRouteOpts are the defaulting routing options which apply
31: // to the root route of a routing tree.
32: var DefaultRouteOpts = RouteOpts{
33: 	GroupWait:         30 * time.Second,
34: 	GroupInterval:     5 * time.Minute,
35: 	RepeatInterval:    4 * time.Hour,
36: 	GroupBy:           map[model.LabelName]struct{}{},
37: 	GroupByAll:        false,
38: 	MuteTimeIntervals: []string{},
39: }
40: 
41: // A Route is a node that contains definitions of how to handle alerts.
42: type Route struct {
43: 	parent *Route
44: 
45: 	// The configuration parameters for matches of this route.
46: 	RouteOpts RouteOpts
47: 
48: 	// Matchers an alert has to fulfill to match
49: 	// this route.
50: 	Matchers labels.Matchers
51: 
52: 	// If true, an alert matches further routes on the same level.
53: 	Continue bool
54: 
55: 	// Children routes of this route.
56: 	Routes []*Route
57: }
58: 
59: // NewRoute returns a new route.
60: func NewRoute(cr *config.Route, parent *Route) *Route {
61: 	// Create default and overwrite with configured settings.
62: 	opts := DefaultRouteOpts
63: 	if parent != nil {
64: 		opts = parent.RouteOpts
65: 	}
66: 
67: 	if cr.Receiver != "" {
68: 		opts.Receiver = cr.Receiver
69: 	}
70: 
71: 	if cr.GroupBy != nil {
72: 		opts.GroupBy = map[model.LabelName]struct{}{}
73: 		for _, ln := range cr.GroupBy {
74: 			opts.GroupBy[ln] = struct{}{}
75: 		}
76: 		opts.GroupByAll = false
77: 	} else {
78: 		if cr.GroupByAll {
79: 			opts.GroupByAll = cr.GroupByAll
80: 		}
81: 	}
82: 
83: 	if cr.GroupWait != nil {
84: 		opts.GroupWait = time.Duration(*cr.GroupWait)
85: 	}
86: 	if cr.GroupInterval != nil {
87: 		opts.GroupInterval = time.Duration(*cr.GroupInterval)
88: 	}
89: 	if cr.RepeatInterval != nil {
90: 		opts.RepeatInterval = time.Duration(*cr.RepeatInterval)
91: 	}
92: 
93: 	// Build matchers.
94: 	var matchers labels.Matchers
95: 
96: 	// cr.Match will be deprecated. This for loop appends matchers.
97: 	for ln, lv := range cr.Match {
98: 		matcher, err := labels.NewMatcher(labels.MatchEqual, ln, lv)
99: 		if err != nil {
100: 			// This error must not happen because the config already validates the yaml.
101: 			panic(err)
102: 		}
103: 		matchers = append(matchers, matcher)
104: 	}
105: 
106: 	// cr.MatchRE will be deprecated. This for loop appends regex matchers.
107: 	for ln, lv := range cr.MatchRE {
108: 		matcher, err := labels.NewMatcher(labels.MatchRegexp, ln, lv.String())
109: 		if err != nil {
110: 			// This error must not happen because the config already validates the yaml.
111: 			panic(err)
112: 		}
113: 		matchers = append(matchers, matcher)
114: 	}
115: 
116: 	// We append the new-style matchers. This can be simplified once the deprecated matcher syntax is removed.
117: 	matchers = append(matchers, cr.Matchers...)
118: 
119: 	sort.Sort(matchers)
120: 
121: 	opts.MuteTimeIntervals = cr.MuteTimeIntervals
122: 	opts.ActiveTimeIntervals = cr.ActiveTimeIntervals
123: 
124: 	route := &Route{
125: 		parent:    parent,
126: 		RouteOpts: opts,
127: 		Matchers:  matchers,
128: 		Continue:  cr.Continue,
129: 	}
130: 
131: 	route.Routes = NewRoutes(cr.Routes, route)
132: 
133: 	return route
134: }
135: 
136: // NewRoutes returns a slice of routes.
137: func NewRoutes(croutes []*config.Route, parent *Route) []*Route {
138: 	res := []*Route{}
139: 	for _, cr := range croutes {
140: 		res = append(res, NewRoute(cr, parent))
141: 	}
142: 	return res
143: }
144: 
145: // Match does a depth-first left-to-right search through the route tree
146: // and returns the matching routing nodes.
147: func (r *Route) Match(lset model.LabelSet) []*Route {
148: 	if !r.Matchers.Matches(lset) {
149: 		return nil
150: 	}
151: 
152: 	var all []*Route
153: 
154: 	for _, cr := range r.Routes {
155: 		matches := cr.Match(lset)
156: 
157: 		all = append(all, matches...)
158: 
159: 		if matches != nil && !cr.Continue {
160: 			break
161: 		}
162: 	}
163: 
164: 	// If no child nodes were matches, the current node itself is a match.
165: 	if len(all) == 0 {
166: 		all = append(all, r)
167: 	}
168: 
169: 	return all
170: }
171: 
172: // Key returns a key for the route. It does not uniquely identify the route in general.
173: func (r *Route) Key() string {
174: 	b := strings.Builder{}
175: 
176: 	if r.parent != nil {
177: 		b.WriteString(r.parent.Key())
178: 		b.WriteRune('/')
179: 	}
180: 	b.WriteString(r.Matchers.String())
181: 	return b.String()
182: }
183: 
184: // ID returns a unique identifier for the route.
185: func (r *Route) ID() string {
186: 	b := strings.Builder{}
187: 
188: 	if r.parent != nil {
189: 		b.WriteString(r.parent.ID())
190: 		b.WriteRune('/')
191: 	}
192: 
193: 	b.WriteString(r.Matchers.String())
194: 
195: 	if r.parent != nil {
196: 		for i := range r.parent.Routes {
197: 			if r == r.parent.Routes[i] {
198: 				b.WriteRune('/')
199: 				b.WriteString(strconv.Itoa(i))
200: 				break
201: 			}
202: 		}
203: 	}
204: 
205: 	return b.String()
206: }
207: 
208: // Walk traverses the route tree in depth-first order.
209: func (r *Route) Walk(visit func(*Route)) {
210: 	visit(r)
211: 	for i := range r.Routes {
212: 		r.Routes[i].Walk(visit)
213: 	}
214: }
215: 
216: // RouteOpts holds various routing options necessary for processing alerts
217: // that match a given route.
218: type RouteOpts struct {
219: 	// The identifier of the associated notification configuration.
220: 	Receiver string
221: 
222: 	// What labels to group alerts by for notifications.
223: 	GroupBy map[model.LabelName]struct{}
224: 
225: 	// Use all alert labels to group.
226: 	GroupByAll bool
227: 
228: 	// How long to wait to group matching alerts before sending
229: 	// a notification.
230: 	GroupWait      time.Duration
231: 	GroupInterval  time.Duration
232: 	RepeatInterval time.Duration
233: 
234: 	// A list of time intervals for which the route is muted.
235: 	MuteTimeIntervals []string
236: 
237: 	// A list of time intervals for which the route is active.
238: 	ActiveTimeIntervals []string
239: }
240: 
241: func (ro *RouteOpts) String() string {
242: 	var labels []model.LabelName
243: 	for ln := range ro.GroupBy {
244: 		labels = append(labels, ln)
245: 	}
246: 	return fmt.Sprintf("<RouteOpts send_to:%q group_by:%q group_by_all:%t timers:%q|%q>",
247: 		ro.Receiver, labels, ro.GroupByAll, ro.GroupWait, ro.GroupInterval)
248: }
249: 
250: // MarshalJSON returns a JSON representation of the routing options.
251: func (ro *RouteOpts) MarshalJSON() ([]byte, error) {
252: 	v := struct {
253: 		Receiver       string           `json:"receiver"`
254: 		GroupBy        model.LabelNames `json:"groupBy"`
255: 		GroupByAll     bool             `json:"groupByAll"`
256: 		GroupWait      time.Duration    `json:"groupWait"`
257: 		GroupInterval  time.Duration    `json:"groupInterval"`
258: 		RepeatInterval time.Duration    `json:"repeatInterval"`
259: 	}{
260: 		Receiver:       ro.Receiver,
261: 		GroupByAll:     ro.GroupByAll,
262: 		GroupWait:      ro.GroupWait,
263: 		GroupInterval:  ro.GroupInterval,
264: 		RepeatInterval: ro.RepeatInterval,
265: 	}
266: 	for ln := range ro.GroupBy {
267: 		v.GroupBy = append(v.GroupBy, ln)
268: 	}
269: 
270: 	return json.Marshal(&v)
271: }
