14: // Package silence provides a storage for silences, which can share its
15: // state over a mesh network and snapshot it.
16: package silence
17: 
18: import (
19: 	"bytes"
20: 	"errors"
21: 	"fmt"
22: 	"io"
23: 	"log/slog"
24: 	"math/rand"
25: 	"os"
26: 	"reflect"
27: 	"regexp"
28: 	"sort"
29: 	"sync"
30: 	"time"
31: 
32: 	"github.com/coder/quartz"
33: 	uuid "github.com/gofrs/uuid"
34: 	"github.com/matttproud/golang_protobuf_extensions/pbutil"
35: 	"github.com/prometheus/client_golang/prometheus"
36: 	"github.com/prometheus/common/model"
37: 	"github.com/prometheus/common/promslog"
38: 
39: 	"github.com/prometheus/alertmanager/cluster"
40: 	"github.com/prometheus/alertmanager/matcher/compat"
41: 	"github.com/prometheus/alertmanager/pkg/labels"
42: 	pb "github.com/prometheus/alertmanager/silence/silencepb"
43: 	"github.com/prometheus/alertmanager/types"
44: )
45: 
46: // ErrNotFound is returned if a silence was not found.
47: var ErrNotFound = errors.New("silence not found")
48: 
49: // ErrInvalidState is returned if the state isn't valid.
50: var ErrInvalidState = errors.New("invalid state")
51: 
52: type matcherCache map[string]labels.Matchers
53: 
54: // Get retrieves the matchers for a given silence. If it is a missed cache
55: // access, it compiles and adds the matchers of the requested silence to the
56: // cache.
57: func (c matcherCache) Get(s *pb.Silence) (labels.Matchers, error) {
58: 	if m, ok := c[s.Id]; ok {
59: 		return m, nil
60: 	}
61: 	return c.add(s)
62: }
63: 
64: // add compiles a silences' matchers and adds them to the cache.
65: // It returns the compiled matchers.
66: func (c matcherCache) add(s *pb.Silence) (labels.Matchers, error) {
67: 	ms := make(labels.Matchers, len(s.Matchers))
68: 
69: 	for i, m := range s.Matchers {
70: 		var mt labels.MatchType
71: 		switch m.Type {
72: 		case pb.Matcher_EQUAL:
73: 			mt = labels.MatchEqual
74: 		case pb.Matcher_NOT_EQUAL:
75: 			mt = labels.MatchNotEqual
76: 		case pb.Matcher_REGEXP:
77: 			mt = labels.MatchRegexp
78: 		case pb.Matcher_NOT_REGEXP:
79: 			mt = labels.MatchNotRegexp
80: 		default:
81: 			return nil, fmt.Errorf("unknown matcher type %q", m.Type)
82: 		}
83: 		matcher, err := labels.NewMatcher(mt, m.Name, m.Pattern)
84: 		if err != nil {
85: 			return nil, err
86: 		}
87: 
88: 		ms[i] = matcher
89: 	}
90: 
91: 	c[s.Id] = ms
92: 	return ms, nil
93: }
94: 
95: // Silencer binds together a AlertMarker and a Silences to implement the Muter
96: // interface.
97: type Silencer struct {
98: 	silences *Silences
99: 	marker   types.AlertMarker
100: 	logger   *slog.Logger
101: }
102: 
103: // NewSilencer returns a new Silencer.
104: func NewSilencer(s *Silences, m types.AlertMarker, l *slog.Logger) *Silencer {
105: 	return &Silencer{
106: 		silences: s,
107: 		marker:   m,
108: 		logger:   l,
109: 	}
110: }
111: 
112: // Mutes implements the Muter interface.
113: func (s *Silencer) Mutes(lset model.LabelSet) bool {
114: 	fp := lset.Fingerprint()
115: 	activeIDs, pendingIDs, markerVersion, _ := s.marker.Silenced(fp)
116: 
117: 	var (
118: 		err        error
119: 		allSils    []*pb.Silence
120: 		newVersion = markerVersion
121: 	)
122: 	if markerVersion == s.silences.Version() {
123: 		totalSilences := len(activeIDs) + len(pendingIDs)
124: 		// No new silences added, just need to check which of the old
125: 		// silences are still relevant and which of the pending ones
126: 		// have become active.
127: 		if totalSilences == 0 {
128: 			// Super fast path: No silences ever applied to this
129: 			// alert, none have been added. We are done.
130: 			return false
131: 		}
132: 		// This is still a quite fast path: No silences have been added,
133: 		// we only need to check which of the applicable silences are
134: 		// currently active. Note that newVersion is left at
135: 		// markerVersion because the Query call might already return a
136: 		// newer version, which is not the version our old list of
137: 		// applicable silences is based on.
138: 		allIDs := append(append(make([]string, 0, totalSilences), activeIDs...), pendingIDs...)
139: 		allSils, _, err = s.silences.Query(
140: 			QIDs(allIDs...),
141: 			QState(types.SilenceStateActive, types.SilenceStatePending),
142: 		)
143: 	} else {
144: 		// New silences have been added, do a full query.
145: 		allSils, newVersion, err = s.silences.Query(
146: 			QState(types.SilenceStateActive, types.SilenceStatePending),
147: 			QMatches(lset),
148: 		)
149: 	}
150: 	if err != nil {
151: 		s.logger.Error("Querying silences failed, alerts might not get silenced correctly", "err", err)
152: 	}
153: 	if len(allSils) == 0 {
154: 		// Easy case, neither active nor pending silences anymore.
155: 		s.marker.SetActiveOrSilenced(fp, newVersion, nil, nil)
156: 		return false
157: 	}
158: 	// It is still possible that nothing has changed, but finding out is not
159: 	// much less effort than just recreating the IDs from the query
160: 	// result. So let's do it in any case. Note that we cannot reuse the
161: 	// current ID slices for concurrency reasons.
162: 	activeIDs, pendingIDs = nil, nil
163: 	now := s.silences.nowUTC()
164: 	for _, sil := range allSils {
165: 		switch getState(sil, now) {
166: 		case types.SilenceStatePending:
167: 			pendingIDs = append(pendingIDs, sil.Id)
168: 		case types.SilenceStateActive:
169: 			activeIDs = append(activeIDs, sil.Id)
170: 		default:
171: 			// Do nothing, silence has expired in the meantime.
172: 		}
173: 	}
174: 	s.logger.Debug(
175: 		"determined current silences state",
176: 		"now", now,
177: 		"total", len(allSils),
178: 		"active", len(activeIDs),
179: 		"pending", len(pendingIDs),
180: 	)
181: 	sort.Strings(activeIDs)
182: 	sort.Strings(pendingIDs)
183: 
184: 	s.marker.SetActiveOrSilenced(fp, newVersion, activeIDs, pendingIDs)
185: 
186: 	return len(activeIDs) > 0
187: }
