321: // Options exposes configuration options for creating a new Silences object.
322: // Its zero value is a safe default.
323: type Options struct {
324: 	// A snapshot file or reader from which the initial state is loaded.
325: 	// None or only one of them must be set.
326: 	SnapshotFile   string
327: 	SnapshotReader io.Reader
328: 
329: 	// Retention time for newly created Silences. Silences may be
330: 	// garbage collected after the given duration after they ended.
331: 	Retention time.Duration
