346: // New returns a new Silences object with the given configuration.
347: func New(o Options) (*Silences, error) {
348: 	if err := o.validate(); err != nil {
349: 		return nil, err
350: 	}
351: 
352: 	s := &Silences{
353: 		clock:     quartz.NewReal(),
354: 		mc:        matcherCache{},
355: 		logger:    promslog.NewNopLogger(),
356: 		retention: o.Retention,
357: 		limits:    o.Limits,
358: 		broadcast: func([]byte) {},
359: 		st:        state{},
360: 	}
361: 	s.metrics = newMetrics(o.Metrics, s)
362: 
363: 	if o.Logger != nil {
364: 		s.logger = o.Logger
365: 	}
366: 
367: 	if o.SnapshotFile != "" {
368: 		if r, err := os.Open(o.SnapshotFile); err != nil {
369: 			if !os.IsNotExist(err) {
370: 				return nil, err
371: 			}
372: 			s.logger.Debug("silences snapshot file doesn't exist", "err", err)
373: 		} else {
374: 			o.SnapshotReader = r
375: 			defer r.Close()
376: 		}
377: 	}
378: 
379: 	if o.SnapshotReader != nil {
380: 		if err := s.loadSnapshot(o.SnapshotReader); err != nil {
381: 			return s, err
382: 		}
383: 	}
384: 	return s, nil
385: }
