491: func validateMatcher(m *pb.Matcher) error {
492: 	if !compat.IsValidLabelName(model.LabelName(m.Name)) {
493: 		return fmt.Errorf("invalid label name %q", m.Name)
494: 	}
495: 	switch m.Type {
496: 	case pb.Matcher_EQUAL, pb.Matcher_NOT_EQUAL:
497: 		if !model.LabelValue(m.Pattern).IsValid() {
498: 			return fmt.Errorf("invalid label value %q", m.Pattern)
499: 		}
500: 	case pb.Matcher_REGEXP, pb.Matcher_NOT_REGEXP:
501: 		if _, err := regexp.Compile(m.Pattern); err != nil {
502: 			return fmt.Errorf("invalid regular expression %q: %w", m.Pattern, err)
503: 		}
504: 	default:
505: 		return fmt.Errorf("unknown matcher type %q", m.Type)
506: 	}
507: 	return nil
508: }
509: 
510: func matchesEmpty(m *pb.Matcher) bool {
511: 	switch m.Type {
512: 	case pb.Matcher_EQUAL:
513: 		return m.Pattern == ""
514: 	case pb.Matcher_REGEXP:
515: 		matched, _ := regexp.MatchString(m.Pattern, "")
516: 		return matched
517: 	default:
518: 		return false
519: 	}
520: }
521: 
522: func validateSilence(s *pb.Silence) error {
523: 	if len(s.Matchers) == 0 {
524: 		return errors.New("at least one matcher required")
525: 	}
526: 	allMatchEmpty := true
527: 
528: 	for i, m := range s.Matchers {
529: 		if err := validateMatcher(m); err != nil {
530: 			return fmt.Errorf("invalid label matcher %d: %w", i, err)
531: 		}
532: 		allMatchEmpty = allMatchEmpty && matchesEmpty(m)
533: 	}
534: 	if allMatchEmpty {
535: 		return errors.New("at least one matcher must not match the empty string")
536: 	}
537: 	if s.StartsAt.IsZero() {
538: 		return errors.New("invalid zero start timestamp")
539: 	}
540: 	if s.EndsAt.IsZero() {
541: 		return errors.New("invalid zero end timestamp")
542: 	}
543: 	if s.EndsAt.Before(s.StartsAt) {
544: 		return errors.New("end time must not be before start time")
545: 	}
546: 	return nil
547: }
