580: func (s *Silences) setSilence(msil *pb.MeshSilence, now time.Time) error {
581: 	b, err := marshalMeshSilence(msil)
582: 	if err != nil {
583: 		return err
584: 	}
585: 	_, added := s.st.merge(msil, now)
586: 	if added {
587: 		s.version++
588: 	}
589: 	s.broadcast(b)
590: 	return nil
